<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-like Desktop</title>
<style>
  * { box-sizing: border-box; }
  body, html {
    margin: 0; padding: 0; width: 100%; height: 100%;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
    overflow: hidden;
  }
  #desktop {
    position: absolute; top: 0; left: 0; right: 0; bottom: 0;
    background: radial-gradient(circle at 50% 40%, #5a1e3d 0%, #2c001e 100%);
    overflow: hidden;
  }
  #taskbar {
    position: absolute; bottom: 0; left: 0; right: 0; height: 56px;
    background: rgba(24, 24, 24, 0.9);
    border-top: 1px solid #444;
    display: flex; align-items: center; padding: 0 16px; gap: 12px;
    backdrop-filter: blur(8px);
  }
  .launcher {
    background: #333; color: #eee; border: 1px solid #555;
    border-radius: 8px; padding: 8px 16px; cursor: pointer;
    font-size: 14px; font-weight: 500; transition: background 0.2s;
  }
  .launcher:hover { background: #444; }

  .window {
    position: absolute; width: 480px; height: 340px;
    background: #2d2d2d; border: 1px solid #111; border-radius: 10px;
    box-shadow: 0 12px 36px rgba(0,0,0,0.6); display: none;
    flex-direction: column; overflow: hidden; color: #eee;
  }
  .title-bar {
    background: #1f1f1f; padding: 10px 14px; display: flex;
    justify-content: space-between; align-items: center;
    cursor: move; border-bottom: 1px solid #111; user-select: none;
  }
  .title-bar span { font-weight: 600; font-size: 14px; }
  .win-close {
    background: #e95420; color: #fff; border: none; border-radius: 50%;
    width: 22px; height: 22px; cursor: pointer; font-size: 14px;
    line-height: 22px; text-align: center; padding: 0; font-weight: bold;
  }
  .win-close:hover { background: #c0411a; }
  .window-body { flex: 1; display: flex; flex-direction: column; overflow: hidden; }

  /* Files */
  .toolbar {
    padding: 8px 12px; background: #252525; border-bottom: 1px solid #111;
    display: flex; align-items: center; gap: 12px;
  }
  #files-up {
    background: #333; color: #eee; border: 1px solid #555; border-radius: 4px;
    padding: 4px 10px; cursor: pointer; font-size: 13px;
  }
  #files-up:hover { background: #444; }
  #files-path {
    font-family: 'Ubuntu Mono', monospace; font-size: 14px; color: #ddd;
  }
  #files-list {
    flex: 1; padding: 12px; overflow-y: auto;
    display: flex; flex-direction: column; gap: 4px;
  }
  .fs-item {
    padding: 6px 10px; cursor: pointer; border-radius: 4px;
    font-family: 'Ubuntu Mono', monospace; font-size: 14px;
    display: flex; align-items: center; gap: 8px;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.folder { font-weight: bold; color: #fff; }
  .fs-item.file { color: #ccc; }

  /* Notepad */
  #tabs-container {
    background: #252525; border-bottom: 1px solid #111;
    display: flex; align-items: stretch; overflow-x: auto;
  }
  #tabs { display: flex; }
  .tab {
    padding: 10px 14px; background: #2d2d2d; border-right: 1px solid #111;
    cursor: pointer; white-space: nowrap; font-size: 13px; color: #bbb;
    display: flex; align-items: center; gap: 8px; user-select: none;
  }
  .tab:hover { background: #353535; }
  .tab.active { background: #1f1f1f; color: #fff; border-bottom: 2px solid #e95420; }
  .tab-close { color: #888; font-weight: bold; padding: 0 2px; }
  .tab-close:hover { color: #e74c3c; }
  #new-tab {
    padding: 10px 14px; background: #333; color: #eee; border: none;
    border-right: 1px solid #111; cursor: pointer; font-size: 14px;
  }
  #new-tab:hover { background: #444; }
  #editor {
    flex: 1; background: #1f1f1f; color: #eee; border: none; padding: 14px;
    font-family: 'Ubuntu Mono', monospace; font-size: 14px; resize: none; outline: none;
    line-height: 1.5;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files" class="launcher">📁 Files</button>
    <button id="open-notepad" class="launcher">📝 Notepad</button>
  </div>

  <div id="files-window" class="window" style="left: 80px; top: 80px;">
    <div class="title-bar">
      <span>Files</span>
      <button class="win-close" title="Close">×</button>
    </div>
    <div class="window-body">
      <div class="toolbar">
        <button id="files-up">⬆ Up</button>
        <span id="files-path">/</span>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <div id="notepad-window" class="window" style="left: 200px; top: 140px;">
    <div class="title-bar">
      <span>Notepad</span>
      <button class="win-close" title="Close">×</button>
    </div>
    <div class="window-body">
      <div id="tabs-container">
        <div id="tabs"></div>
        <button id="new-tab">+ New Tab</button>
      </div>
      <textarea id="editor" placeholder="Type here..."></textarea>
    </div>
  </div>
</div>

<script>
  // Filesystem Data
  const filesystem = {
    '/': ['bin', 'etc', 'home', 'usr', 'var'],
    '/bin': ['bash', 'ls', 'cp', 'mv'],
    '/etc': ['passwd', 'hosts', 'resolv.conf', 'network'],
    '/home': ['user'],
    '/home/user': ['Documents', 'Downloads', 'Pictures', 'readme.txt'],
    '/home/user/Documents': ['todo.txt', 'notes.md', 'resume.pdf'],
    '/home/user/Downloads': ['ubuntu.iso', 'music.mp3', 'archive.zip'],
    '/home/user/Pictures': ['wallpaper.png', 'selfie.jpg', 'screenshot.png'],
    '/usr': ['bin', 'lib', 'share', 'local'],
    '/var': ['log', 'www', 'cache', 'tmp']
  };

  let currentPath = '/';

  function getChildren(path) {
    if (path === '/') return filesystem['/'];
    let p = path.endsWith('/') ? path.slice(0, -1) : path;
    return filesystem[p] || [];
  }

  function isFolder(path, name) {
    let childPath = path === '/' ? '/' + name : path + '/' + name;
    return Array.isArray(filesystem[childPath]);
  }

  function renderFiles() {
    document.getElementById('files-path').textContent = currentPath;
    const list = document.getElementById('files-list');
    list.innerHTML = '';
    const children = getChildren(currentPath);
    if (children.length === 0) {
      const empty = document.createElement('div');
      empty.style.color = '#888';
      empty.style.padding = '8px';
      empty.textContent = '(empty)';
      list.appendChild(empty);
      return;
    }
    children.forEach(name => {
      const item = document.createElement('div');
      item.className = 'fs-item ' + (isFolder(currentPath, name) ? 'folder' : 'file');
      item.textContent = name;
      if (isFolder(currentPath, name)) {
        item.addEventListener('dblclick', () => {
          currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
          renderFiles();
        });
      }
      list.appendChild(item);
    });
  }

  document.getElementById('files-up').addEventListener('click', () => {
    if (currentPath === '/') return;
    let parts = currentPath.split('/');
    parts.pop();
    currentPath = parts.join('/') || '/';
    renderFiles();
  });

  // Notepad Logic
  let notepadState = { tabs: [], activeId: null };
  const STORAGE_KEY = 'ubuntu_notepad_state';

  function loadNotepad() {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        notepadState = JSON.parse(saved);
      }
    } catch(e) {
      notepadState = { tabs: [], activeId: null };
    }
    if (!notepadState.tabs || notepadState.tabs.length === 0) {
      createTab();
    } else {
      if (!notepadState.tabs.find(t => t.id === notepadState.activeId)) {
        notepadState.activeId = notepadState.tabs[0].id;
      }
      renderTabs();
      updateEditor();
    }
  }

  function saveNotepad() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(notepadState));
    } catch(e) {}
  }

  function createTab() {
    const id = 'tab_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
    const tabNum = notepadState.tabs.length + 1;
    notepadState.tabs.push({ id, title: 'Tab ' + tabNum, content: '' });
    notepadState.activeId = id;
    saveNotepad();
    renderTabs();
    updateEditor();
  }

  function closeTab(id) {
    notepadState.tabs = notepadState.tabs.filter(t => t.id !== id);
    if (notepadState.activeId === id) {
      notepadState.activeId = notepadState.tabs.length > 0 ? notepadState.tabs[0].id : null;
    }
    if (notepadState.tabs.length === 0) {
      createTab();
    } else {
      saveNotepad();
      renderTabs();
      updateEditor();
    }
  }

  function renderTabs() {
    const tabsContainer = document.getElementById('tabs');
    tabsContainer.innerHTML = '';
    notepadState.tabs.forEach(tab => {
      const el = document.createElement('div');
      el.className = 'tab' + (tab.id === notepadState.activeId ? ' active' : '');

      const titleSpan = document.createElement('span');
      titleSpan.textContent = tab.title;
      el.appendChild(titleSpan);

      const closeBtn = document.createElement('span');
      closeBtn.className = 'tab-close';
      closeBtn.textContent = '×';
      closeBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        closeTab(tab.id);
      });
      el.appendChild(closeBtn);

      el.addEventListener('click', () => {
        notepadState.activeId = tab.id;
        saveNotepad();
        renderTabs();
        updateEditor();
      });
      tabsContainer.appendChild(el);
    });
  }

  function updateEditor() {
    const editor = document.getElementById('editor');
    const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeId);
    editor.value = activeTab ? activeTab.content : '';
  }

  document.getElementById('editor').addEventListener('input', (e) => {
    const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeId);
    if (activeTab) {
      activeTab.content = e.target.value;
      saveNotepad();
    }
  });

  document.getElementById('new-tab').addEventListener('click', createTab);

  // Window Management
  document.getElementById('open-files').addEventListener('click', () => {
    document.getElementById('files-window').style.display = 'flex';
    renderFiles();
  });

  document.getElementById('open-notepad').addEventListener('click', () => {
    document.getElementById('notepad-window').style.display = 'flex';
  });

  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.target.closest('.window').style.display = 'none';
    });
  });

  // Draggable Windows
  function makeDraggable(win) {
    const titleBar = win.querySelector('.title-bar');
    let isDragging = false;
    let offsetX, offsetY;
    titleBar.addEventListener('mousedown', (e) => {
      if (e.target.classList.contains('win-close')) return;
      isDragging = true;
      offsetX = e.clientX - win.offsetLeft;
      offsetY = e.clientY - win.offsetTop;
      document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
      win.style.zIndex = 20;
    });
    document.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      win.style.left = (e.clientX - offsetX) + 'px';
      win.style.top = (e.clientY - offsetY) + 'px';
    });
    document.addEventListener('mouseup', () => {
      isDragging = false;
    });
  }

  makeDraggable(document.getElementById('files-window'));
  makeDraggable(document.getElementById('notepad-window'));

  // Init
  renderFiles();
  loadNotepad();
</script>
</body>
</html>
